import { Geist, Geist_Mono, Inter } from 'next/font/google';
import { cn } from '@/lib/utils';

const fontSans = Geist({
  subsets: ['latin'],
  variable: '--font-sans'
});

const fontMono = Geist_Mono({
  subsets: ['latin'],
  variable: '--font-mono'
});

const fontInter = Inter({
  subsets: ['latin'],
  variable: '--font-inter'
});

export const fontVariables = cn(
  fontSans.variable,
  fontMono.variable,
  fontInter.variable,
  // Fallbacks for removed fonts to avoid breaking other variables if they were used
  '--font-instrument',
  '--font-noto-mono',
  '--font-mullish',
  '--font-architects-daughter',
  '--font-dm-sans',
  '--font-fira-code',
  '--font-outfit',
  '--font-space-mono'
);
